testcase.Script:
var hsms = this.ta.get("/api/hsms");

for (var i = 0; i< hsms.length; i++) {
	this.assertTrue(hsms[i].id, "Must return a list of hsms");

	var hsm = this.ta.get("/api/hsms/" + hsms[i].id);
	this.assertTrue(hsm.id, "Must return a single hsm entry");
}

var hsms = this.ta.get("/api/hsms");

for (var i = 0; i < hsms.length; i++) {
	this.assertTrue(hsms[i].id, "Must return a list of hsms");

	var keys = this.ta.get("/api/hsms/" + hsms[i].id + "/keys");

	for (var j = 0; j < keys.length; j++) {
		this.assertTrue(keys[j].id, "Must return a list of keys");

		var key = this.ta.get("/api/hsms/" + hsms[i].id + "/keys/" + keys[j].id);

		this.assertTrue(key.id, "Must return a single key entry");
	}
}

var keys = this.ta.get("/api/keys");

for (var i = 0; i< keys.length; i++) {
	this.assertTrue(keys[i].id, "Must return a list of keys");

	var key = this.ta.get("/api/keys/" + keys[i].id);
	this.assertTrue(key.id, "Must return a single key entry");
}

var keydomains = this.ta.get("/api/keydomains");

for (var i = 0; i< keydomains.length; i++) {
	this.assertTrue(keydomains[i].id, "Must return a list of key domains");

	var keydomain = this.ta.get("/api/keydomains/" + keydomains[i].id);
	this.assertTrue(keydomain.id, "Must return a single key domain entry");
}

var keydomains = this.ta.get("/api/keydomains");

for (var i = 0; i < keydomains.length; i++) {
	this.assertTrue(keydomains[i].id, "Must return a list of key domains");

	var keys = this.ta.get("/api/keydomains/" + keydomains[i].id + "/keys");

	for (var j = 0; j < keys.length; j++) {
		this.assertTrue(keys[j].id, "Must return a list of keys");

		var key = this.ta.get("/api/keydomains/" + keydomains[i].id + "/keys/" + keys[j].id);

		this.assertTrue(key.id, "Must return a single key entry");
	}
}
